#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000

int isTrapped(char grid[][MAX], int n, int m, int i, int j) {
    if (i == 0 || i == n - 1 || j == 0 || j == m - 1) return 0;
    if (grid[i - 1][j] == 'W' || grid[i + 1][j] == 'W' || grid[i][j - 1] == 'W' || grid[i][j + 1] == 'W') return 0;
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        char grid[n][MAX];
        for (int i = 0; i < n; i++) scanf("%s", grid[i]);
        int found = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (grid[i][j] == 'W') {
                    int trapped = 1;
                    for (int k = 0; k < n; k++) {
                        for (int l = 0; l < m; l++) {
                            if (k == i || l == j) grid[k][l] = 'W';
                        }
                    }
                    int allTrapped = 1;
                    for (int k = 0; k < n; k++) {
                        for (int l = 0; l < m; l++) {
                            if (grid[k][l] == 'W' && isTrapped(grid, n, m, k, l)) {
                                allTrapped = 0;
                                break;
                            }
                        }
                        if (!allTrapped) break;
                    }
                    if (allTrapped) {
                        found = 1;
                        break;
                    }
                    for (int k = 0; k < n; k++) {
                        for (int l = 0; l < m; l++) {
                            if (k == i || l == j) grid[k][l] = (k == i && l == j) ? 'W' : 'B';
                        }
                    }
                }
            }
            if (found) break;
        }
        printf(found ? "YES\n" : "NO\n");
    }
    return 0;
}

